    87→iree_status_t Run() {
    88→  iree_status_t status = iree_ok_status();
    89→
    90→  iree_runtime_instance_options_t instance_options;
    91→  iree_runtime_instance_options_initialize(&instance_options);
    92→  iree_runtime_instance_options_use_all_available_drivers(&instance_options);
    93→  iree_runtime_instance_t* instance = NULL;
    94→
    95→  IREE_RETURN_IF_ERROR(
    96→    iree_runtime_instance_create(&instance_options,
    97→                                          iree_allocator_system(), &instance), " instance create");
    98→
    99→  // Create dylib device with static loader.
   100→  iree_hal_device_t* device = NULL;
   101→  IREE_RETURN_IF_ERROR(
   102→    create_device_with_static_loader(iree_allocator_system(), &device), "create device");
   103→
   104→  // Session configuration (one per loaded module to hold module state).
   105→  iree_runtime_session_options_t session_options;
   106→  iree_runtime_session_options_initialize(&session_options);
   107→  iree_runtime_session_t* session = NULL;
   108→  if (iree_status_is_ok(status)) {
   109→    status = iree_runtime_session_create_with_device(
   110→        instance, &session_options, device,
   111→        iree_runtime_instance_host_allocator(instance), &session);
   112→  }
   113→
   114→
   115→  // Load bytecode module from the embedded data. Append to the session.
   116→  iree_vm_module_t* module = NULL;
   117→
   118→  IREE_RETURN_IF_ERROR(
   119→    create_module(iree_runtime_instance_vm_instance(instance), &module), "create module");
   120→
   121→  IREE_RETURN_IF_ERROR(
   122→    iree_runtime_session_append_module(session, module),
   123→    "session append module");
   124→
   125→  // Lookup the entry point function call.
   126→  const char kMainFunctionName[] = _FUNC;
   127→  iree_runtime_call_t call;
   128→  memset(&call, 0, sizeof(call));
   129→  IREE_RETURN_IF_ERROR(
   130→    iree_runtime_call_initialize_by_name(
   131→        session, iree_make_cstring_view(kMainFunctionName), &call),
   132→    "init call");
   133→
   134→  iree_vm_list_t* inputs;
   135→  IREE_CHECK_OK(iree_vm_list_create(iree_vm_make_value_type_def(IREE_VM_VALUE_TYPE_I32), 1,
   136→                                    iree_allocator_system(), &inputs));
   137→  iree_vm_value_t arg_value = iree_vm_value_make_i32(1);
   138→  IREE_RETURN_IF_ERROR(iree_vm_list_push_value(inputs, &arg_value));
   139→
   140→  iree_vm_list_t* outputs = NULL;
   141→  IREE_CHECK_OK(iree_vm_list_create(iree_vm_make_value_type_def(IREE_VM_VALUE_TYPE_I32), 1,
   142→                                    iree_allocator_system(), &outputs));
   143→
   144→  printf("tune...ok\n");
   145→//  clock_t start, end;
   146→//  start = clock();
   147→#ifdef PF_COUNTER
   148→    startPFM;
   149→#endif
   150→  IREE_CHECK_OK(
   151→      iree_runtime_session_call_by_name(session, iree_make_cstring_view(kMainFunctionName), inputs, outputs));
   152→#ifdef PF_COUNTER
   153→    stopPFM;
   154→    readResult();
   155→#endif
   156→//  end = clock();
   157→//  double diff = end - start; // ms
   158→  printf(" PASS1 \n");
   159→//  printf("seconds : %f  PASS2 \n", diff / CLOCKS_PER_SEC );
   160→  iree_runtime_call_deinitialize(&call);
   161→
   162→  // Cleanup session and instance.
   163→  iree_hal_device_release(device);
   164→  iree_runtime_session_release(session);
   165→  iree_runtime_instance_release(instance);
   166→  iree_vm_module_release(module);
   167→
   168→  return status;
   169→}
   170→
   171→int main(int argc, char** argv) {
   172→  __asm__ __volatile__ ( " csrs mstatus,  %0" :: "r"((unsigned long) 1 << 9) );
   173→
   174→  iree_status_t result = Run();
   175→  if (!iree_status_is_ok(result)) {
   176→    iree_status_fprint(stderr, result);
   177→    iree_status_ignore(result);
   178→    return -1;
   179→  }
   180→  iree_status_ignore(result);
   181→  return 0;
   182→}
